def findFarmland(land):
    m, n = len(land), len(land[0])
    groups = []

    for i in range(m):
        for j in range(n):
            if land[i][j] == 1:
                r1, c1 = i, j
                while j + 1 < n and land[i][j + 1] == 1:
                    j += 1
                r2, c2 = i, j
                while r2 + 1 < m and land[r2 + 1][j] == 1:
                    r2 += 1
                for r in range(r1, r2 + 1):
                    for c in range(c1, c2 + 1):
                        land[r][c] = 0
                groups.append([r1, c1, r2, c2])

    return groups
